function msel_h(mixed $value): string
{
    return htmlspecialchars((string)$value, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8');
}

function msel_csrf(): string
{
    if (empty($_SESSION['mobile_submit_evidence_log_csrf']) || !is_string($_SESSION['mobile_submit_evidence_log_csrf'])) {
        $_SESSION['mobile_submit_evidence_log_csrf'] = bin2hex(random_bytes(32));
    }
    return $_SESSION['mobile_submit_evidence_log_csrf'];
}

function msel_validate_csrf(string $token): bool
{
    return isset($_SESSION['mobile_submit_evidence_log_csrf'])
        && is_string($_SESSION['mobile_submit_evidence_log_csrf'])
        && hash_equals($_SESSION['mobile_submit_evidence_log_csrf'], $token);
}

function msel_app_context(?string &$error = null): ?array
{
    static $ctx = null;
    static $loaded = false;
    static $loadError = null;

    if ($loaded) {
        $error = $loadError;
        return is_array($ctx) ? $ctx : null;
    }

    $loaded = true;
    $bootstrap = dirname(__DIR__, 3) . '/gov.cabnet.app_app/src/bootstrap.php';
    if (!is_file($bootstrap)) {
        $loadError = 'Private app bootstrap not found.';
        $error = $loadError;
        return null;
    }

    try {
        $ctx = require $bootstrap;
        if (!is_array($ctx)) {
            throw new RuntimeException('Private app bootstrap did not return a context array.');
        }
        $error = null;
        return $ctx;
    } catch (Throwable $e) {
        $loadError = $e->getMessage();
        $error = $loadError;
        return null;
    }
}

function msel_db(?string &$error = null): ?mysqli
{
    $ctx = msel_app_context($error);
    if (!$ctx || !isset($ctx['db']) || !method_exists($ctx['db'], 'connection')) {
        $error = $error ?: 'Private DB context is unavailable.';
        return null;
    }
    try {
        $db = $ctx['db']->connection();
        if (!$db instanceof mysqli) {
            throw new RuntimeException('DB context did not return mysqli.');
        }
        return $db;
    } catch (Throwable $e) {
        $error = $e->getMessage();
        return null;
    }
}

function msel_table_exists(mysqli $db, string $table): bool
{
    try {
        $stmt = $db->prepare('SELECT TABLE_NAME FROM information_schema.TABLES WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = ? LIMIT 1');
        $stmt->bind_param('s', $table);
        $stmt->execute();
        return (bool)$stmt->get_result()->fetch_assoc();
    } catch (Throwable) {
        return false;
    }
}

function msel_current_user(): array
{
    if (function_exists('opsui_current_user')) {
        return opsui_current_user();
    }
    $user = $_SESSION['ops_user'] ?? [];
    return is_array($user) ? $user : [];
}

function msel_is_admin(): bool
{
    if (function_exists('opsui_is_admin')) {
        return opsui_is_admin();
    }
    $user = msel_current_user();
    return strtolower((string)($user['role'] ?? 'operator')) === 'admin';
}

function msel_badge(string $text, string $type = 'neutral'): string
{
