        return opsui_badge($text, $type);
    }
    return '<span class="badge badge-' . msel_h($type) . '">' . msel_h($text) . '</span>';
}

function msel_contains_forbidden_content(string $json, array &$matches): bool
{
    $patterns = [
        '/Operator:\s*/i' => 'raw_bolt_email_operator_line',
        '/Customer mobile:\s*/i' => 'raw_bolt_email_customer_mobile_line',
        '/Pickup:\s*/i' => 'raw_bolt_email_pickup_line',
        '/Drop-off:\s*/i' => 'raw_bolt_email_dropoff_line',
        '/PHPSESSID|laravel_session|remember_web|XSRF-TOKEN/i' => 'session_or_cookie_pattern',
        '/BEGIN\s+(RSA|OPENSSH|PRIVATE)\s+KEY/i' => 'private_key_pattern',
        '/("|\')?(password|passwd|secret|credential|private_key|cookie_value|session_value|csrf_token_value)("|\')?\s*[:=]/i' => 'secret_like_key_pattern',
    ];

    foreach ($patterns as $pattern => $label) {
        if (preg_match($pattern, $json)) {
            $matches[] = $label;
        }
    }

    return $matches !== [];
}

/**
 * @param mixed $value
 * @return mixed
 */
function msel_sanitize_value(mixed $value, string $keyPath = ''): mixed
{
    if (is_array($value)) {
        $out = [];
        foreach ($value as $key => $child) {
            $keyText = (string)$key;
            $childPath = $keyPath === '' ? $keyText : $keyPath . '.' . $keyText;
            if (msel_is_sensitive_json_key($keyText, $childPath)) {
                $out[$key] = '__REDACTED_BY_EVIDENCE_LOG__';
            } else {
                $out[$key] = msel_sanitize_value($child, $childPath);
            }
        }
        return $out;
    }

    if (is_string($value)) {
        if (preg_match('/PHPSESSID|laravel_session|remember_web|XSRF-TOKEN|BEGIN\s+(RSA|OPENSSH|PRIVATE)\s+KEY/i', $value)) {
            return '__REDACTED_BY_EVIDENCE_LOG__';
        }
        if (strlen($value) > 20000) {
            return substr($value, 0, 20000) . '\n__TRUNCATED_BY_EVIDENCE_LOG__';
        }
    }

    return $value;
}

function msel_is_sensitive_json_key(string $key, string $path): bool
{
    $name = strtolower($key);
    $full = strtolower($path);

    $allowed = [
        'csrf_field_name',
        'csrf_field_name_from_capture',
        'csrf_field_name_detected',
        'raw_email_sha256',
        'email_sha256',
        'source_email_sha256',
    ];
    if (in_array($name, $allowed, true)) {
        return false;
    }

    if (in_array($name, ['raw_email', 'raw_email_text', 'email_text', 'source_email_text', 'message_body'], true)) {
        return true;
    }

    return (bool)preg_match('/(^|_)(password|passwd|secret|credential|cookie|session|csrf_token|token_value|private_key)(_|$)/i', $name)
        || str_contains($full, 'raw_email_text')
        || str_contains($full, 'email_text');
}

/** @param mixed $node */
function msel_find_first($node, array $keys): string
{
    if (!is_array($node)) {
        return '';
    }
    foreach ($keys as $key) {
        if (array_key_exists($key, $node) && !is_array($node[$key]) && trim((string)$node[$key]) !== '') {
            return trim((string)$node[$key]);
        }
    }
    foreach ($node as $child) {
        if (is_array($child)) {
            $found = msel_find_first($child, $keys);
            if ($found !== '') {
                return $found;
            }
        }
    }
    return '';
}

function msel_normalize_json(string $raw, array &$meta, array &$errors): string
{
    $raw = trim($raw);
    if ($raw === '') {
        $errors[] = 'Evidence JSON is empty.';
        return '';
    }

    $matches = [];
    if (msel_contains_forbidden_content($raw, $matches)) {
        $errors[] = 'Evidence JSON appears to contain raw email text or secret/session patterns: ' . implode(', ', array_unique($matches));
        return '';
    }

    $decoded = json_decode($raw, true);
    if (!is_array($decoded)) {
        $errors[] = 'Evidence JSON could not be parsed: ' . json_last_error_msg();
        return '';
    }

    $sanitized = msel_sanitize_value($decoded);
    $json = json_encode($sanitized, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
    if (!is_string($json) || $json === '') {
        $errors[] = 'Sanitized evidence JSON could not be encoded.';
        return '';
    }

    $meta = [
        'evidence_sha256' => hash('sha256', $json),
        'email_sha256' => msel_find_first($sanitized, ['raw_email_sha256', 'email_sha256', 'source_email_sha256']),
        'final_status' => msel_find_first($sanitized, ['final_status', 'trial_status', 'decision', 'status']),
        'lessor_id' => msel_find_first($sanitized, ['lessor_id', 'lessorId']),
        'driver_id' => msel_find_first($sanitized, ['driver_id', 'driverId']),
        'vehicle_id' => msel_find_first($sanitized, ['vehicle_id', 'vehicleId']),
        'starting_point_id' => msel_find_first($sanitized, ['starting_point_id', 'startingPointId']),
    ];

    return $json;
}

function msel_fetch_recent(mysqli $db): array
{
    if (!msel_table_exists($db, 'mobile_submit_evidence_log')) {
        return [];
    }
    $rows = [];
    $res = $db->query('SELECT id, evidence_sha256, email_sha256, source_label, final_status, lessor_id, driver_id, vehicle_id, starting_point_id, notes, created_by_username, created_at FROM mobile_submit_evidence_log ORDER BY id DESC LIMIT 100');
    if ($res) {
        while ($row = $res->fetch_assoc()) {
            $rows[] = $row;
        }
    }
    return $rows;
}

function msel_download_json(mysqli $db, int $id): void
{
    $stmt = $db->prepare('SELECT id, evidence_sha256, evidence_json FROM mobile_submit_evidence_log WHERE id = ? LIMIT 1');
    $stmt->bind_param('i', $id);
    $stmt->execute();
    $row = $stmt->get_result()->fetch_assoc();
    if (!$row) {
        http_response_code(404);
        echo 'Not found.';
        exit;
    }
    $name = 'mobile_submit_evidence_' . (int)$row['id'] . '_' . substr((string)$row['evidence_sha256'], 0, 12) . '.json';
    header_remove('Content-Type');
    header('Content-Type: application/json; charset=utf-8');
    header('Content-Disposition: attachment; filename="' . $name . '"');
    header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
    echo (string)$row['evidence_json'];
    exit;
}

$dbError = null;
$db = msel_db($dbError);
$tableReady = $db instanceof mysqli && msel_table_exists($db, 'mobile_submit_evidence_log');
$csrf = msel_csrf();
$message = '';
$messageType = 'neutral';
$postedJson = '';
$postedNotes = '';
$postedSource = '';

if ($db && $tableReady && isset($_GET['download'])) {
    msel_download_json($db, max(0, (int)$_GET['download']));
}

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $postedJson = (string)($_POST['evidence_json'] ?? '');
    $postedNotes = trim((string)($_POST['notes'] ?? ''));
    $postedSource = trim((string)($_POST['source_label'] ?? ''));

    try {
        if (!msel_is_admin()) {
            throw new RuntimeException('Admin role is required to save evidence.');
        }
        if (!msel_validate_csrf((string)($_POST['csrf'] ?? ''))) {
            throw new RuntimeException('Security token expired. Please reload and try again.');
        }
        if (!$db) {
            throw new RuntimeException('DB unavailable: ' . (string)$dbError);
        }
        if (!$tableReady) {
            throw new RuntimeException('Table mobile_submit_evidence_log is not installed. Run the Phase 59 SQL migration first.');
        }

        $meta = [];
        $errors = [];
        $normalized = msel_normalize_json($postedJson, $meta, $errors);
        if ($errors !== []) {
            throw new RuntimeException(implode(' ', $errors));
        }

        $user = msel_current_user();
        $userId = (int)($user['id'] ?? 0);
        $username = trim((string)($user['username'] ?? $user['display_name'] ?? ''));
        $source = $postedSource !== '' ? $postedSource : 'mobile-submit-evidence.php';

        $stmt = $db->prepare("INSERT INTO mobile_submit_evidence_log
            (evidence_sha256, email_sha256, source_label, final_status, lessor_id, driver_id, vehicle_id, starting_point_id, evidence_json, notes, created_by_user_id, created_by_username, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW())
            ON DUPLICATE KEY UPDATE
                source_label = VALUES(source_label),
                final_status = VALUES(final_status),
                lessor_id = VALUES(lessor_id),
                driver_id = VALUES(driver_id),
                vehicle_id = VALUES(vehicle_id),
                starting_point_id = VALUES(starting_point_id),
                evidence_json = VALUES(evidence_json),
                notes = VALUES(notes),
                created_by_user_id = VALUES(created_by_user_id),
                created_by_username = VALUES(created_by_username),
                created_at = NOW()");
        $stmt->bind_param(
            'ssssssssssis',
            $meta['evidence_sha256'],
            $meta['email_sha256'],
            $source,
            $meta['final_status'],
            $meta['lessor_id'],
            $meta['driver_id'],
            $meta['vehicle_id'],
            $meta['starting_point_id'],
            $normalized,
            $postedNotes,
            $userId,
            $username
        );
        $stmt->execute();

        $message = 'Sanitized evidence saved. SHA-256: ' . $meta['evidence_sha256'];
        $messageType = 'good';
        $postedJson = '';
        $postedNotes = '';
        $postedSource = '';
    } catch (Throwable $e) {
        $message = $e->getMessage();
        $messageType = 'bad';
    }
}

